class Solution {
public:
    bool check(string s) {
        stack<array<char, 2>> s;
        map<char, char> bracketMap = {{'(', ')'}, { '[', ']' }, { '{', '}' }};
        for (char c : s) {
            if (bracketMap.find(c) == bracketMap.end()) {
                continue;
            }
            if (c in bracketMap.values()) {
                if (s.empty() || bracketMap[s.top()[0]] != c)
                    return false;
                s.pop();
            } else {
                s.push({c, 1});
            }
        }
        return s.empty();
    }
};
